+    expect(payload.messages[2]).not.toHaveProperty("reasoning_content");
+    expect(payload.messages[3]).toHaveProperty("reasoning_content", "");
+    expect(payload.messages[4]).toHaveProperty("reasoning_content", "native reasoning");
+  });
+});
